// Fast-path for --version/-v: zero module loading needed
if (args.length === 1 && (args[0] === '--version' || args[0] === '-v' || args[0] === '-V')) {
  console.log(`${MACRO.VERSION} (Claude Code)`);
  return;
}

// Fast-path for template job commands
if (feature('TEMPLATES') && (args[0] === 'new' || args[0] === 'list' || args[0] === 'reply')) {
  const { templatesMain } = await import('../cli/handlers/templateJobs.js');
  await templatesMain(args);
  process.exit(0);
}

// Pre-fetch promises - only items needed before render
const skipPluginPrefetch = getIsNonInteractiveSession() || isBareMode()
if (!skipPluginPrefetch) {
  void getCommands(getProjectRoot()) // 并行预取命令
}

void import('./utils/plugins/loadPluginHooks.js').then(m => {
  if (!skipPluginPrefetch) {
    void m.loadPluginHooks() // 预加载插件钩子
    m.setupPluginHookHotReload() // 设置热重载
  }
})

// Check for Node.js version < 18
const nodeVersion = process.version.match(/^v(\d+)\./)?.[1]
if (!nodeVersion || parseInt(nodeVersion) < 18) {
  console.error('Error: Claude Code requires Node.js version 18 or higher.')
  process.exit(1)
}

// Handle worktree creation if requested
if (worktreeEnabled) {
  const worktreeSession = await createWorktreeForSession(
    getSessionId(),
    slug,
    tmuxSessionName,
    worktreePRNumber ? { prNumber: worktreePRNumber } : undefined
  )
  process.chdir(worktreeSession.worktreePath)
}
